import React, { useState } from "react";
import axios from "axios";

const servicosDisponiveis = [
    "Administração de medicamentos",
    "Controle de sinais vitais (pressão, glicemia, temperatura)",
    "Auxílio em higiene pessoal (banho, troca de fraldas)",
    "Auxílio em alimentação (preparo e administração, inclusive via sonda)",
    "Auxílio em locomoção e transferência",
    "Acompanhamento a consultas e exames",
    "Exercícios de estimulação cognitiva",
    "Exercícios físicos leves / fisioterapia básica",
    "Curativos simples",
    "Manuseio de equipamentos (oxigênio, aspirador, cadeira de rodas)",
    "Cuidados noturnos",
    "Preparo de refeições especiais (dietas restritivas)",
    "Tarefas domésticas leves"
];

function CadastrarMotoristaComponent() {
    const [nome, setNome] = useState("");
    const [cpf, setCpf] = useState("");
    const [dataNascimento, setDataNascimento] = useState("");
    const [telefone, setTelefone] = useState("");
    const [email, setEmail] = useState("");
    const [ativo, setAtivo] = useState(true);
    const [cnh, setCnh] = useState("");
    const [coren, setCoren] = useState("");
    const [disponivel, setDisponivel] = useState(true);
    const [aprovado, setAprovado] = useState(false);
    const [servicoSelecionado, setServicoSelecionado] = useState("");
    const [servicosSelecionados, setServicosSelecionados] = useState<string[]>([]);
    const [loading, setLoading] = useState(false);
    const [mensagem, setMensagem] = useState<string | null>(null);

    const inserirServico = () => {
        if (!servicoSelecionado) {
            return;
        }
        if (servicosSelecionados.includes(servicoSelecionado)) {
            return;
        }
        setServicosSelecionados((prev) => [...prev, servicoSelecionado]);
        setServicoSelecionado("");
    };

    const removerServico = (servico: string) => {
        setServicosSelecionados((prev) => prev.filter((item) => item !== servico));
    };

    const limparFormulario = () => {
        setNome("");
        setCpf("");
        setDataNascimento("");
        setTelefone("");
        setEmail("");
        setAtivo(true);
        setCnh("");
        setCoren("");
        setDisponivel(true);
        setAprovado(false);
        setServicosSelecionados([]);
        setServicoSelecionado("");
    };

    const handleSubmit = async (event: React.FormEvent) => {
        event.preventDefault();
        setMensagem(null);
        setLoading(true);

        try {
            await axios.post("http://localhost:8080/motoristas", {
                nome,
                cpf,
                dataNascimento,
                telefone,
                email,
                ativo,
                cnh,
                coren,
                disponivel,
                aprovado,
                servicos: servicosSelecionados.join(", ")
            });
            setMensagem("Motorista cadastrado com sucesso.");
            limparFormulario();
        } catch (error) {
            setMensagem("Erro ao cadastrar motorista.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="container">
            <h2 className="mb-4">Cadastrar Motorista</h2>
            {mensagem && (
                <div className="alert alert-info">{mensagem}</div>
            )}
            <form onSubmit={handleSubmit}>
                <div className="row">
                    <div className="col-md-6 mb-3">
                        <label className="form-label">Nome:</label>
                        <input
                            type="text"
                            className="form-control"
                            value={nome}
                            onChange={(e) => setNome(e.target.value)}
                            disabled={loading}
                            required
                        />
                    </div>
                    <div className="col-md-6 mb-3">
                        <label className="form-label">CPF:</label>
                        <input
                            type="text"
                            className="form-control"
                            value={cpf}
                            onChange={(e) => setCpf(e.target.value)}
                            disabled={loading}
                            required
                        />
                    </div>
                </div>

                <div className="row">
                    <div className="col-md-6 mb-3">
                        <label className="form-label">Data de Nascimento:</label>
                        <input
                            type="date"
                            className="form-control"
                            value={dataNascimento}
                            onChange={(e) => setDataNascimento(e.target.value)}
                            disabled={loading}
                            required
                        />
                    </div>
                    <div className="col-md-6 mb-3">
                        <label className="form-label">CNH:</label>
                        <input
                            type="text"
                            className="form-control"
                            value={cnh}
                            onChange={(e) => setCnh(e.target.value)}
                            disabled={loading}
                            required
                        />
                    </div>
                </div>

                <div className="row">
                    <div className="col-md-6 mb-3">
                        <label className="form-label">Telefone:</label>
                        <input
                            type="text"
                            className="form-control"
                            value={telefone}
                            onChange={(e) => setTelefone(e.target.value)}
                            disabled={loading}
                        />
                    </div>
                    <div className="col-md-6 mb-3">
                        <label className="form-label">Email:</label>
                        <input
                            type="email"
                            className="form-control"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            disabled={loading}
                        />
                    </div>
                </div>

                <div className="row">
                    <div className="col-md-6 mb-3">
                        <label className="form-label">COREN:</label>
                        <input
                            type="text"
                            className="form-control"
                            value={coren}
                            onChange={(e) => setCoren(e.target.value)}
                            disabled={loading}
                        />
                    </div>
                </div>

                <div className="mb-3">
                    <label className="form-label">Serviços:</label>
                    <div className="row g-2">
                        <div className="col-md-8">
                            <select
                                className="form-select"
                                value={servicoSelecionado}
                                onChange={(e) => setServicoSelecionado(e.target.value)}
                                disabled={loading}
                            >
                                <option value="">Selecione um serviço</option>
                                {servicosDisponiveis.map((servico) => (
                                    <option key={servico} value={servico}>
                                        {servico}
                                    </option>
                                ))}
                            </select>
                        </div>
                        <div className="col-md-4 d-grid">
                            <button
                                type="button"
                                className="btn btn-secondary"
                                onClick={inserirServico}
                                disabled={loading || !servicoSelecionado}
                            >
                                Inserir
                            </button>
                        </div>
                    </div>
                    {servicosSelecionados.length > 0 && (
                        <div className="mt-3">
                            <div className="d-flex flex-wrap gap-2">
                                {servicosSelecionados.map((servico) => (
                                    <span key={servico} className="badge bg-primary">
                                        {servico}
                                        <button
                                            type="button"
                                            className="btn btn-sm btn-light ms-2"
                                            onClick={() => removerServico(servico)}
                                            disabled={loading}
                                        >
                                            x
                                        </button>
                                    </span>
                                ))}
                            </div>
                        </div>
                    )}
                </div>

                <div className="row">
                    <div className="col-md-4 mb-3">
                        <div className="form-check">
                            <input
                                className="form-check-input"
                                type="checkbox"
                                checked={ativo}
                                onChange={(e) => setAtivo(e.target.checked)}
                                disabled={loading}
                                id="motoristaAtivo"
                            />
                            <label className="form-check-label" htmlFor="motoristaAtivo">
                                Ativo
                            </label>
                        </div>
                    </div>
                    <div className="col-md-4 mb-3">
                        <div className="form-check">
                            <input
                                className="form-check-input"
                                type="checkbox"
                                checked={disponivel}
                                onChange={(e) => setDisponivel(e.target.checked)}
                                disabled={loading}
                                id="motoristaDisponivel"
                            />
                            <label className="form-check-label" htmlFor="motoristaDisponivel">
                                Disponível
                            </label>
                        </div>
                    </div>
                    <div className="col-md-4 mb-3">
                        <div className="form-check">
                            <input
                                className="form-check-input"
                                type="checkbox"
                                checked={aprovado}
                                onChange={(e) => setAprovado(e.target.checked)}
                                disabled={loading}
                                id="motoristaAprovado"
                            />
                            <label className="form-check-label" htmlFor="motoristaAprovado">
                                Aprovado
                            </label>
                        </div>
                    </div>
                </div>

                <button type="submit" className="btn btn-primary" disabled={loading}>
                    Cadastrar Motorista
                </button>
            </form>
            {loading && <div className="loading-footer">Carregando...</div>}
        </div>
    );
}

export default CadastrarMotoristaComponent;
